from fastapi import FastAPI, Depends, HTTPException, status, Header
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from typing import Optional, Dict, Any
import redis.asyncio as redis
from contextlib import asynccontextmanager
import json
from datetime import datetime

redis_client: Optional[redis.Redis] = None

@asynccontextmanager
async def lifespan(app: FastAPI):
    global redis_client
    redis_client = redis.Redis(
        host='localhost',
        port=6379,
        db=0,
        decode_responses=True
    )
    await redis_client.ping()
    yield
    await redis_client.close()

app = FastAPI(lifespan=lifespan)

security = HTTPBearer()

class TokenValidator:
    def __init__(self, redis_client: redis.Redis):
        self.redis_client = redis_client
    
    async def validate_token(self, token: str) -> Dict[str, Any]:
        token_data = await self.redis_client.get(f"token:{token}")
        
        if not token_data:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Invalid or expired token",
                headers={"WWW-Authenticate": "Bearer"},
            )
        
        try:
            return json.loads(token_data)
        except json.JSONDecodeError:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Invalid token format",
                headers={"WWW-Authenticate": "Bearer"},
            )

async def get_token_validator() -> TokenValidator:
    return TokenValidator(redis_client)

async def get_current_user(
    credentials: HTTPAuthorizationCredentials = Depends(security),
    validator: TokenValidator = Depends(get_token_validator)
) -> Dict[str, Any]:
    token = credentials.credentials
    user_data = await validator.validate_token(token)
    return user_data

async def get_current_active_user(
    current_user: Dict[str, Any] = Depends(get_current_user)
) -> Dict[str, Any]:
    if not current_user.get("active", True):
        raise HTTPException(
            status_code=status.HTTP_403_FORBIDDEN,
            detail="Inactive user"
        )
    return current_user

async def get_admin_user(
    current_user: Dict[str, Any] = Depends(get_current_active_user)
) -> Dict[str, Any]:
    if current_user.get("role") != "admin":
        raise HTTPException(
            status_code=status.HTTP_403_FORBIDDEN,
            detail="Admin privileges required"
        )
    return current_user

@app.post("/auth/token")
async def create_token(username: str, user_id: str, role: str = "user", ttl: int = 3600):
    token = f"token_{username}_{user_id}_{int(datetime.utcnow().timestamp())}"
    
    token_data = {
        "user_id": user_id,
        "username": username,
        "role": role,
        "active": True,
        "created_at": datetime.utcnow().isoformat()
    }
    
    await redis_client.setex(
        f"token:{token}",
        ttl,
        json.dumps(token_data)
    )
    
    return {
        "access_token": token,
        "token_type": "bearer",
        "expires_in": ttl
    }

