@app.delete("/auth/token")
async def revoke_token(
    credentials: HTTPAuthorizationCredentials = Depends(security)
):
    token = credentials.credentials
    deleted = await redis_client.delete(f"token:{token}")
    
    if deleted:
        return {"message": "Token revoked successfully"}
    else:
        raise HTTPException(
            status_code=status.HTTP_404_NOT_FOUND,
            detail="Token not found"
        )

@app.get("/health")
async def health_check():
    try:
        await redis_client.ping()
        return {"status": "healthy", "redis": "connected"}
    except Exception as e:
        return {"status": "unhealthy", "redis": "disconnected", "error": str(e)}

@app.post("/auth/refresh")
async def refresh_token(
    current_user: Dict[str, Any] = Depends(get_current_user),
    credentials: HTTPAuthorizationCredentials = Depends(security),
    ttl: int = 3600
):
    old_token = credentials.credentials
    
    new_token = f"token_{current_user['username']}_{current_user['user_id']}_{int(datetime.utcnow().timestamp())}"
    
    token_data = {
        "user_id": current_user["user_id"],
        "username": current_user["username"],
        "role": current_user["role"],
        "active": current_user["active"],
        "created_at": datetime.utcnow().isoformat()
    }
    
    await redis_client.setex(
        f"token:{new_token}",
        ttl,
        json.dumps(token_data)
    )
    
    await redis_client.delete(f"token:{old_token}")
    
    return {
        "access_token": new_token,
        "token_type": "bearer",
        "expires_in": ttl
    }